import Anthropic from "@anthropic-ai/sdk";

const client = new Anthropic();

const stream = client.messages.stream({
  model: "claude-opus-4-8",
  max_tokens: 2048,
  messages: [{ role: "user", content: "Write a fairy tale about a gardener robot" }],
});

stream.on("text", (delta) => process.stdout.write(delta)); // print piece by piece

const full = await stream.finalMessage(); // and at the end — the full message
console.log("\nOutput tokens:", full.usage.output_tokens);
